import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';

interface User {
  _id: string;
  name: string;
  email: string;
  role: string;
  isActive: boolean;
}

interface Stats {
  totalUsers: number;
  activeUsers: number;
  totalProjects: number;
  totalTasks: number;
  projectsByStatus: { [key: string]: number };
  tasksByStatus: { [key: string]: number };
}

const AdminDashboard: React.FC = () => {
  const [users, setUsers] = useState<User[]>([]);
  const [stats, setStats] = useState<Stats | null>(null);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    fetchAdminData();
  }, []);

  const fetchAdminData = async () => {
    try {
      const token = localStorage.getItem('token');
      
      // Fetch users
      const usersRes = await fetch('http://localhost:5000/api/admin/users', {
        headers: { 'Authorization': `Bearer ${token}` }
      });
      const usersData = await usersRes.json();
      if (usersData.success) {
        setUsers(usersData.data);
      }

      // Fetch stats
      const statsRes = await fetch('http://localhost:5000/api/admin/stats', {
        headers: { 'Authorization': `Bearer ${token}` }
      });
      const statsData = await statsRes.json();
      if (statsData.success) {
        setStats(statsData.data);
      }
    } catch (error) {
      console.error('Error fetching admin data:', error);
    } finally {
      setLoading(false);
    }
  };

  const updateUserRole = async (userId: string, newRole: string) => {
    try {
      const token = localStorage.getItem('token');
      const response = await fetch(`http://localhost:5000/api/admin/users/${userId}/role`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
        body: JSON.stringify({ role: newRole })
      });
      
      if (response.ok) {
        fetchAdminData();
      }
    } catch (error) {
      console.error('Error updating user role:', error);
    }
  };

  const deleteUser = async (userId: string) => {
    if (!window.confirm('Are you sure you want to delete this user?')) return;
    
    try {
      const token = localStorage.getItem('token');
      const response = await fetch(`http://localhost:5000/api/admin/users/${userId}`, {
        method: 'DELETE',
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });
      
      if (response.ok) {
        fetchAdminData();
      }
    } catch (error) {
      console.error('Error deleting user:', error);
    }
  };

  const getRoleColor = (role: string) => {
    const colors: { [key: string]: string } = {
      admin: '#dc3545',
      project_manager: '#fd7e14',
      developer: '#0066cc',
      reviewer: '#28a745',
      viewer: '#6c757d'
    };
    return colors[role] || '#6c757d';
  };

  if (loading) {
    return <div style={styles.loading}>Loading admin dashboard...</div>;
  }

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <h1 style={styles.title}>🔐 Admin Dashboard</h1>
        <button onClick={() => navigate('/dashboard')} style={styles.backBtn}>
          ← Back to Dashboard
        </button>
      </div>

      {/* Stats Cards */}
      <div style={styles.statsGrid}>
        <div style={styles.statCard}>
          <div style={styles.statNumber}>{stats?.totalUsers || 0}</div>
          <div style={styles.statLabel}>Total Users</div>
        </div>
        <div style={styles.statCard}>
          <div style={styles.statNumber}>{stats?.activeUsers || 0}</div>
          <div style={styles.statLabel}>Active Users</div>
        </div>
        <div style={styles.statCard}>
          <div style={styles.statNumber}>{stats?.totalProjects || 0}</div>
          <div style={styles.statLabel}>Total Projects</div>
        </div>
        <div style={styles.statCard}>
          <div style={styles.statNumber}>{stats?.totalTasks || 0}</div>
          <div style={styles.statLabel}>Total Tasks</div>
        </div>
      </div>

      {/* Project Status */}
      <div style={styles.section}>
        <h3 style={styles.sectionTitle}>📊 Project Status</h3>
        <div style={styles.statusGrid}>
          {stats?.projectsByStatus && Object.entries(stats.projectsByStatus).map(([status, count]) => (
            <div key={status} style={styles.statusItem}>
              <span style={styles.statusLabel}>{status}</span>
              <span style={styles.statusCount}>{count}</span>
            </div>
          ))}
        </div>
      </div>

      {/* Task Status */}
      <div style={styles.section}>
        <h3 style={styles.sectionTitle}>📋 Task Status</h3>
        <div style={styles.statusGrid}>
          {stats?.tasksByStatus && Object.entries(stats.tasksByStatus).map(([status, count]) => (
            <div key={status} style={styles.statusItem}>
              <span style={styles.statusLabel}>{status.replace('_', ' ')}</span>
              <span style={styles.statusCount}>{count}</span>
            </div>
          ))}
        </div>
      </div>

      {/* Users Table */}
      <div style={styles.section}>
        <h3 style={styles.sectionTitle}>👥 User Management</h3>
        <div style={styles.tableContainer}>
          <table style={styles.table}>
            <thead>
              <tr>
                <th>Name</th>
                <th>Email</th>
                <th>Role</th>
                <th>Status</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {users.map((user) => (
                <tr key={user._id}>
                  <td>{user.name}</td>
                  <td>{user.email}</td>
                  <td>
                    <select
                      value={user.role}
                      onChange={(e) => updateUserRole(user._id, e.target.value)}
                      style={{
                        ...styles.roleSelect,
                        backgroundColor: getRoleColor(user.role),
                        color: 'white'
                      }}
                    >
                      <option value="admin">Admin</option>
                      <option value="project_manager">Project Manager</option>
                      <option value="developer">Developer</option>
                      <option value="reviewer">Reviewer</option>
                      <option value="viewer">Viewer</option>
                    </select>
                  </td>
                  <td>
                    <span style={{
                      ...styles.statusBadge,
                      backgroundColor: user.isActive ? '#28a745' : '#dc3545'
                    }}>
                      {user.isActive ? 'Active' : 'Inactive'}
                    </span>
                  </td>
                  <td>
                    <button
                      onClick={() => deleteUser(user._id)}
                      style={styles.deleteBtn}
                    >
                      Delete
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

